import React, { useState, useEffect } from 'react';
import './Result.css';

function Result({ preview, isHotdog, onReset }) {
  const [animate, setAnimate] = useState(false);

  useEffect(() => {
    // Trigger the banner animation after mount
    const timer = setTimeout(() => setAnimate(true), 100);
    return () => clearTimeout(timer);
  }, []);

  return (
    <div className="result-screen" onClick={onReset}>
      {/* Full-bleed food image */}
      <img src={preview} alt="" className="result-bg" />

      {/* Verdict Banner — positioned like the show */}
      <div className={`verdict-container ${animate ? 'verdict-animate' : ''} ${isHotdog ? 'verdict-hotdog' : 'verdict-not'}`}>
        {/* Circle icon */}
        <div className="verdict-icon-circle">
          {isHotdog ? (
            <svg viewBox="0 0 24 24" className="verdict-icon-svg">
              <polyline
                points="4 12 10 18 20 6"
                fill="none"
                stroke="white"
                strokeWidth="3"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          ) : (
            <svg viewBox="0 0 24 24" className="verdict-icon-svg">
              <line x1="6" y1="6" x2="18" y2="18" stroke="white" strokeWidth="3" strokeLinecap="round" />
              <line x1="18" y1="6" x2="6" y2="18" stroke="white" strokeWidth="3" strokeLinecap="round" />
            </svg>
          )}
        </div>

        {/* Banner */}
        <div className="verdict-banner">
          <h1 className="verdict-text">
            {isHotdog ? 'Hotdog' : 'Not hotdog'}
          </h1>
        </div>
      </div>

      {/* Tap hint */}
      <div className={`tap-hint ${animate ? 'hint-visible' : ''}`}>
        Tap anywhere to try again
      </div>
    </div>
  );
}

export default Result;
